-- Sprint 94 PostgreSQL migration: AI-assisted dispatch recommendations.
CREATE TABLE IF NOT EXISTS ai_dispatch_requests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id text NOT NULL, job_id uuid NOT NULL, customer_id uuid, appointment_id uuid, requested_for timestamptz NOT NULL, service_type text NOT NULL DEFAULT '', priority text NOT NULL DEFAULT 'normal', territory_id uuid, required_skills jsonb NOT NULL DEFAULT '[]'::jsonb, preferred_technician_id uuid, excluded_technician_ids jsonb NOT NULL DEFAULT '[]'::jsonb, candidate_limit integer NOT NULL DEFAULT 5, weights jsonb NOT NULL DEFAULT '{}'::jsonb, metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_dispatch_recommendations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id text NOT NULL, request_id uuid NOT NULL, job_id uuid NOT NULL, status text NOT NULL DEFAULT 'generated', candidates jsonb NOT NULL DEFAULT '[]'::jsonb, selected_technician_id uuid, accepted_by text NOT NULL DEFAULT '', accepted_at timestamptz, rejected_reason text NOT NULL DEFAULT '', generated_at timestamptz NOT NULL, metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_ai_dispatch_requests_tenant_job ON ai_dispatch_requests (tenant_id, job_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_ai_dispatch_requests_tenant_requested ON ai_dispatch_requests (tenant_id, requested_for DESC);
CREATE INDEX IF NOT EXISTS idx_ai_dispatch_recommendations_tenant_job ON ai_dispatch_recommendations (tenant_id, job_id, generated_at DESC);
CREATE INDEX IF NOT EXISTS idx_ai_dispatch_recommendations_tenant_status ON ai_dispatch_recommendations (tenant_id, status, generated_at DESC);
